{{ site.lang }}
{{ site.time | date_to_rfc822 }}
Copyright {{ site.time | date: '%Y' }} {{ company.name | xml_escape }}
{% for assignment in collections.assignments reversed %}


  {{ assignment.data.roles | xml_escape }} at {{ assignment.data.title | xml_escape }}
  {{ assignment.url | absolute_url }}
  {{ assignment.data.start_date | date_to_rfc822 }}

    {{ assignment.data.roles | join: ", "| escape }} at {{ assignment.data.title | xml_escape }}
    {{ assignment.data.start_date }} - {{ assignment.data.end_date }}
    {{ assignment.data.description }}{% for highlight in assignment.data.highlights %}
    {{ highlight | xml_escape }}{% endfor %}
    Skills: {{ assignment.data.skills | normalizeSkills | join: ', ' | xml_escape }}{{ assignment.data.competencies | normalizeSkills | join: ', ' | xml_escape }}

{% endfor %}
